#[doc(alias = "cmpspace")]
pub fn CMPSPACE(cpu: &mut Cpu) {
    match cpu.reg.a {
        0x00 | 0x09 | 0x0c | 0x14 => {
            cpu.set_a(0x00);
            return;
        }
        _ => {}
    }
    if cpu.reg.a < 0x1a {
        cpu.set_a(0x01);
        return;
    }
    cpu.set_a(0x00);
    return;
}

#[doc(alias = "cmpbarr")]
pub fn CMPBARR(cpu: &mut Cpu) {
    match cpu.reg.a {
        0x07 | 0x0c | 0x04 => {
            cpu.set_a(0x01);  // panel/gate
            return;
        }
        _ => {}
    }
    match cpu.reg.a {
        0x0d | 0x12 => {
            cpu.set_a(0x03);  // mirror/slicer
            return;
        }
        _ => {}
    }
    if cpu.reg.a != 0x14 {
        cpu.set_a(0x00);
        return;
    }
    cpu.set_a(0x04);  // block
    return;
}

#[doc(alias = "cmpwall")]
pub fn CMPWALL(cpu: &mut Cpu) {
    'b5: {
        if cpu.reg.a != 0x14 {
            cpu.set_x(cpu.mem[sym::CharFace]);
            if (cpu.reg.x as i8) < 0 {
                if cpu.reg.a == 0x07 {
                    break 'b5;
                } else {
                    if cpu.reg.a == 0x0c {
                        break 'b5;
                    }
                }
            }
            cpu.set_a(0x01);
            return;
        }
    }
    cpu.set_a(0x00);
    return;
}

