pub fn ZERORED(cpu: &mut Cpu) {
    cpu.set_a(0x00);
    cpu.reg.y = 0x1d;
    loop {
        cpu.mem[(sym::redbuf + cpu.reg.y as usize) & 0xffff] = cpu.reg.a;
        cpu.mem[(sym::fredbuf + cpu.reg.y as usize) & 0xffff] = cpu.reg.a;
        cpu.mem[(sym::floorbuf + cpu.reg.y as usize) & 0xffff] = cpu.reg.a;
        cpu.mem[(sym::wipebuf + cpu.reg.y as usize) & 0xffff] = cpu.reg.a;
        cpu.mem[(sym::movebuf + cpu.reg.y as usize) & 0xffff] = cpu.reg.a;
        cpu.mem[(sym::objbuf + cpu.reg.y as usize) & 0xffff] = cpu.reg.a;
        cpu.mem[(sym::halfbuf + cpu.reg.y as usize) & 0xffff] = cpu.reg.a;
        cpu.reg.y = cpu.reg.y.wrapping_sub(0x01);
        if !((cpu.reg.y as i8) >= 0) {
            break;
        }
    }
    cpu.reg.y = 0x09;
    loop {
        cpu.mem[(sym::topbuf + cpu.reg.y as usize) & 0xffff] = cpu.reg.a;
        cpu.reg.y = cpu.reg.y.wrapping_sub(0x01);
        if !((cpu.reg.y as i8) >= 0) {
            break;
        }
    }
    return;
}

#[doc(alias = "checkledge")]
pub fn CHECKLEDGE(cpu: &mut Cpu) {
    'b10: {
        cpu.mem[sym::ztemp] = cpu.reg.a;
        cpu.set_a(cpu.mem[((cpu.mem[sym::BlueSpec] as usize | (cpu.mem[sym::BlueSpec + 1] as usize) << 8) + cpu.reg.y as usize) & 0xffff]);
        cpu.mem[sym::tempstate] = cpu.reg.a;
        cpu.set_a(cpu.mem[sym::blockid]);
        if cpu.reg.a != 0x14 {
            if cpu.reg.a == 0x0c {
                let _o: u8 = cpu.mem[sym::CharFace];
                cpu.flags.z = (cpu.reg.a & _o) == 0;
                cpu.flags.n = (_o >> 7) != 0;
                if !cpu.flags.n {
                    break 'b10;
                }
            }
            CMPSPACE(cpu);
            if cpu.flags.z {
                cpu.set_a(cpu.mem[sym::ztemp]);
                if cpu.reg.a == 0x0b {
                    let _o: u8 = cpu.mem[sym::tempstate];
                    cpu.flags.z = (cpu.reg.a & _o) == 0;
                    cpu.flags.n = (_o >> 7) != 0;
                    if !cpu.flags.z {
                        break 'b10;
                    }
                }
                if cpu.reg.a == 0x07 {
                    let _o: u8 = cpu.mem[sym::CharFace];
                    cpu.flags.z = (cpu.reg.a & _o) == 0;
                    cpu.flags.n = (_o >> 7) != 0;
                    if cpu.flags.n {
                        break 'b10;
                    }
                }
                CMPSPACE(cpu);
                if !cpu.flags.z {
                    cpu.set_a(0x01);
                    return;
                }
            }
        }
    }
    cpu.set_a(0x00);
    return;
}

#[doc(alias = "checkspikes")]
pub fn CHECKSPIKES(cpu: &mut Cpu) {
    let mut pc: u32 = 0;
    loop {
        match pc {
            0 => {
                cpu.set_a(cpu.mem[sym::rightej]);
                GETBLOCKXP(cpu);
                if cpu.flags.n {
                    pc = 4;
                } else {
                    pc = 1;
                }
            }
            1 => {
                cpu.mem[sym::tempright] = cpu.reg.a;
                cpu.set_a(cpu.mem[sym::leftej]);
                GETBLOCKXP(cpu);
                pc = 2;
            }
            2 => {
                cpu.mem[sym::blockx] = cpu.reg.a;
                sub(cpu);
                cpu.set_a(cpu.mem[sym::blockx]);
                let _o: u8 = cpu.mem[sym::tempright];
                cpu.flags.c = cpu.reg.a >= _o;
                cpu.flags.z = cpu.reg.a == _o;
                cpu.flags.n = (cpu.reg.a.wrapping_sub(_o) >> 7) != 0;
                if cpu.reg.a == cpu.mem[sym::tempright] {
                    pc = 4;
                } else {
                    pc = 3;
                }
            }
            3 => {
                cpu.flags.c = false;
                let _r = (cpu.reg.a as u16) + (0x01) as u16 + (cpu.flags.c as u16);
                cpu.flags.c = (_r >> 8) != 0;
                cpu.set_a(_r as u8);
                pc = 2;
            }
            4 => {
                return;
            }
            _ => unreachable!(),
        }
    }
}

pub fn sub(cpu: &mut Cpu) {
    let mut pc: u32 = 0;
    loop {
        match pc {
            0 => {
                cpu.mem[sym::tempblockx] = cpu.reg.a;
                cpu.set_a(cpu.mem[sym::CharBlockY]);
                cpu.mem[sym::tempblocky] = cpu.reg.a;
                cpu.set_a(cpu.mem[sym::CharScrn]);
                cpu.mem[sym::tempscrn] = cpu.reg.a;
                pc = 1;
            }
            1 => {
                RDBLOCK1(cpu);
                let _o: u8 = 0x02;
                cpu.flags.c = cpu.reg.a >= _o;
                cpu.flags.z = cpu.reg.a == _o;
                cpu.flags.n = (cpu.reg.a.wrapping_sub(_o) >> 7) != 0;
                if cpu.reg.a != 0x02 {
                    pc = 3;
                } else {
                    pc = 2;
                }
            }
            2 => {
                crate::mover::TRIGSPIKES(cpu);
                return;
            }
            3 => {
                CMPSPACE(cpu);
                if !cpu.flags.z {
                    pc = 7;
                } else {
                    pc = 4;
                }
            }
            4 => {
                cpu.set_a(cpu.mem[sym::tempscrn]);
                if cpu.reg.a == 0x00 {
                    pc = 7;
                } else {
                    pc = 5;
                }
            }
            5 => {
                let _o: u8 = cpu.mem[sym::CharScrn];
                cpu.flags.c = cpu.reg.a >= _o;
                cpu.flags.z = cpu.reg.a == _o;
                cpu.flags.n = (cpu.reg.a.wrapping_sub(_o) >> 7) != 0;
                if cpu.reg.a != cpu.mem[sym::CharScrn] {
                    pc = 7;
                } else {
                    pc = 6;
                }
            }
            6 => {
                let _v = cpu.mem[sym::tempblocky].wrapping_add(1);
                cpu.mem[sym::tempblocky] = _v;
                cpu.set_nz(_v);
                pc = 1;
            }
            7 => {
                return;
            }
            _ => unreachable!(),
        }
    }
}

#[doc(alias = "LoadKid")]
pub fn LOADKID(cpu: &mut Cpu) {
    cpu.reg.x = 0x0f;
    loop {
        cpu.set_a(cpu.mem[(sym::Kid + cpu.reg.x as usize) & 0xffff]);
        cpu.mem[(sym::Char + cpu.reg.x as usize) & 0xffff] = cpu.reg.a;
        cpu.reg.x = cpu.reg.x.wrapping_sub(0x01);
        if !((cpu.reg.x as i8) >= 0) {
            break;
        }
    }
    return;
}

